1	/**
2	 * Status Server — lightweight HTTP API + Mini App for /status monitoring.
3	 * Independent server on STATUS_PORT (default 3847).
4	 */
5	import { createServer, type Server, type IncomingMessage, type ServerResponse } from "node:http";
6	import { readFile, readdir, stat } from "node:fs/promises";
7	import path from "node:path";
8	import { listTasks, listActiveTasks, getTask, cancelTask } from "./status-store.js";
9	import { getSpecialists, type SpecialistEntry } from "./specialist.js";
10	import { getRecentEvents, type StateEvent } from "./event-log.js";
11	import { config } from "./config.js";
12	
13	let httpServer: Server | undefined;
14	
15	// SSE clients per taskId
16	const sseClients = new Map<string, Set<ServerResponse>>();
17	
18	// ─── Specialist helpers ────────────────────────────────────────────────────
19	
20	/** decodeURIComponent 對無效 percent-encoding（%zz）會 throw URIError，統一轉成 null 讓路由回 400。 */
21	function safeDecode(s: string): string | null {
22	  try { return decodeURIComponent(s); } catch { return null; }
23	}
24	
25	function escapeRegex(s: string): string {
26	  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
27	}
28	
29	/** env 可能含 API key 等機密，回傳前把機密欄位遮罩。 */
30	function maskEnv(env?: Record<string, string>): Record<string, string> | undefined {
31	  if (!env) return env;
32	  return Object.fromEntries(Object.entries(env).map(([k, v]) =>
33	    [k, /key|token|secret|password|credential/i.test(k) ? "••••••" : v]));
34	}
35	
36	function extractModel(entry: SpecialistEntry): string {
37	  const args = entry.harness.args;
38	  const idx = args.indexOf("--model");
39	  return idx >= 0 && idx + 1 < args.length ? args[idx + 1] : "default";
40	}
41	
42	function countRecentTasks(name: string, events: StateEvent[], days: number): number {
43	  const cutoff = new Date();
44	  cutoff.setDate(cutoff.getDate() - days);
45	  const cutoffStr = cutoff.toISOString();
46	  return events.filter(
47	    (e) => e.type === "specialist_spawn" && e.ts >= cutoffStr &&
48	      ((e.payload.name as string) === name || (e.payload.target as string) === name)
49	  ).length;
50	}
51	
52	let factsCache: { ts: number; data: Map<string, Array<{ id: string; timestamp: string; text: string }>> } | null = null;
53	const FACTS_CACHE_TTL = 60_000;
54	
55	async function loadFactsForSpecialist(name: string): Promise<{ totalCount: number; recentFacts: Array<{ id: string; timestamp: string; text: string }> }> {
56	  const now = Date.now();
57	  if (!factsCache || now - factsCache.ts > FACTS_CACHE_TTL) {
58	    factsCache = { ts: now, data: new Map() };
59	    const userId = (process.env.ALLOWED_USER_IDS ?? "").split(",")[0]?.trim();
60	    if (userId) {
61	      const shardDir = path.join(config.memoryDir, "facts_Topic", userId);
62	      try {
63	        const files = await readdir(shardDir);
64	        for (const file of files) {
65	          if (!file.endsWith(".md")) continue;
66	          const content = await readFile(path.join(shardDir, file), "utf8");
67	          const lines = content.split("\n").filter((l) => l.startsWith("- ["));
68	          for (const line of lines) {
69	            // 行格式：- [f_xxx] [ISO timestamp] text（timestamp 可省略）
70	            const m = line.match(/^- \[([^\]]+)\](?:\s+\[([^\]]+)\])?\s+(.+)$/);
71	            if (!m) continue;
72	            const fact = { id: m[1], timestamp: m[2] ?? "", text: m[3] };
73	            for (const sp of getSpecialists()) {
74	              if (line.toLowerCase().includes(sp.name.toLowerCase())) {
75	                if (!factsCache.data.has(sp.name)) factsCache.data.set(sp.name, []);
76	                factsCache.data.get(sp.name)!.push(fact);
77	              }
78	            }
79	          }
80	        }
81	      } catch { /* shardDir may not exist */ }
82	    }
83	  }
84	  const facts = factsCache.data.get(name) ?? [];
85	  return { totalCount: facts.length, recentFacts: facts.slice(-5).reverse() };
86	}
87	
88	export function startStatusServer(port: number): void {
89	  if (httpServer) return;
90	
91	  const staticDir = path.resolve(import.meta.dirname ?? ".", "..", "status-app");
92	
93	  // 前端一律以 location.origin 同源 fetch（localhost 直開 / Mini App tunnel 皆同源），
94	  // 不設 CORS header——避免任意網頁跨源讀取本機 API。
95	  httpServer = createServer((req, res) => {
96	    // 錯誤邊界：async body 任何 throw（如畸形 percent-encoding）只回 500，
97	    // 不能變成 unhandledRejection——index.ts 的全域 handler 會 process.exit(1) 殺掉整個 bridge。
98	    void (async () => {
99	    const url = new URL(req.url ?? "/", `http://localhost:${port}`);
100	    const p = url.pathname;
101	
102	    // ─── API routes ──────────────────────────────────────────────────────
103	    if (p === "/api/status" && req.method === "GET") {
104	      const active = listActiveTasks();
105	      const recent = listTasks().filter((t) => t.status !== "running").slice(-10);
106	      json(res, { active, recent });
107	      return;
108	    }
109	
110	    // SSE stream
111	    const streamMatch = p.match(/^\/api\/status\/([^/]+)\/stream$/);
112	    if (streamMatch && req.method === "GET") {
113	      const taskId = streamMatch[1];
114	      res.writeHead(200, {
115	        "Content-Type": "text/event-stream",
116	        "Cache-Control": "no-cache",
117	        "Connection": "keep-alive",
118	      });
119	      // Register client
120	      if (!sseClients.has(taskId)) sseClients.set(taskId, new Set());
121	      sseClients.get(taskId)!.add(res);
122	      // Send current status immediately
123	      const task = getTask(taskId);
124	      if (task) {
125	        sseSend(res, { type: "status", status: task.status, turns: task.turns });
126	      }
127	      req.on("close", () => {
128	        sseClients.get(taskId)?.delete(res);
129	        if (sseClients.get(taskId)?.size === 0) sseClients.delete(taskId);
130	      });
131	      return;
132	    }
133	
134	    // Cancel
135	    const cancelMatch = p.match(/^\/api\/status\/([^/]+)\/cancel$/);
136	    if (cancelMatch && req.method === "POST") {
137	      const ok = cancelTask(cancelMatch[1]);
138	      if (!ok) json(res, { error: "cannot cancel" }, 400);
139	      else {
140	        broadcastSSE(cancelMatch[1], { type: "status", status: "cancelled" });
141	        json(res, { ok: true });
142	      }
143	      return;
144	    }
145	
146	    // Single task
147	    const taskMatch = p.match(/^\/api\/status\/([^/]+)$/);
148	    if (taskMatch && req.method === "GET") {
149	      const task = getTask(taskMatch[1]);
150	      if (!task) json(res, { error: "not found" }, 404);
151	      else json(res, task);
152	      return;
153	    }
154	
155	    // ─── Specialist API routes ─────────────────────────────────────────
156	    if (p === "/api/specialists" && req.method === "GET") {
157	      const specialists = getSpecialists();
158	      const active = listActiveTasks();
159	      const events = getRecentEvents(2000);
160	      const summaries = specialists.map((sp) => {
161	        const activeTask = active.find((t) => t.specialist === sp.name);
162	        return {
163	          name: sp.name,
164	          model: extractModel(sp),
165	          cwd: sp.cwd,
166	          maxTurns: sp.maxTurns ?? 15,
167	          timeoutMs: sp.timeoutMs ?? 1_800_000,
168	          mcpServers: (sp.mcpServers ?? []).filter((s: any) => !s.disabled).map((s: any) => s.name),
169	          status: activeTask ? "busy" as const : "idle" as const,
170	          activeTaskId: activeTask?.taskId,
171	          recentTaskCount: countRecentTasks(sp.name, events, 7),
172	        };
173	      });
174	      json(res, summaries);
175	      return;
176	    }
177	
178	    const spDetailMatch = p.match(/^\/api\/specialists\/([^/]+)$/);
179	    if (spDetailMatch && req.method === "GET") {
180	      const name = safeDecode(spDetailMatch[1]);
181	      if (name === null) { json(res, { error: "bad name" }, 400); return; }
182	      const sp = getSpecialists().find((s) => s.name === name);
183	      if (!sp) { json(res, { error: "not found" }, 404); return; }
184	      const active = listActiveTasks();
185	      const events = getRecentEvents(2000);
186	      const activeTask = active.find((t) => t.specialist === sp.name);
187	      json(res, {
188	        name: sp.name,
189	        model: extractModel(sp),
190	        cwd: sp.cwd,
191	        maxTurns: sp.maxTurns ?? 15,
192	        timeoutMs: sp.timeoutMs ?? 1_800_000,
193	        mcpServers: (sp.mcpServers ?? []).filter((s: any) => !s.disabled).map((s: any) => s.name),
194	        status: activeTask ? "busy" : "idle",
195	        activeTaskId: activeTask?.taskId,
196	        recentTaskCount: countRecentTasks(sp.name, events, 7),
197	        harness: sp.harness,
198	        env: maskEnv(sp.env),
199	        mcpServersFull: (sp.mcpServers ?? []).filter((s: any) => !s.disabled).map((s: any) => ({
200	          name: s.name, command: s.command, url: s.url,
201	        })),
202	      });
203	      return;
204	    }
205	
206	    const spPreambleMatch = p.match(/^\/api\/specialists\/([^/]+)\/preamble$/);
207	    if (spPreambleMatch && req.method === "GET") {
208	      const name = safeDecode(spPreambleMatch[1]);
209	      // 白名單擋 path traversal（%2E%2E%2F 解碼後可逃出 specialists 目錄）
210	      if (name === null || !getSpecialists().some((s) => s.name === name)) {
211	        json(res, { error: "not found" }, 404);
212	        return;
213	      }
214	      const bridgeDir = path.resolve(config.sessionCwd);
215	      const preamblePath = path.join(bridgeDir, "specialists", name, "preamble.md");
216	      try {
217	        const content = await readFile(preamblePath, "utf8");
218	        json(res, { content });
219	      } catch {
220	        json(res, { error: "preamble not found" }, 404);
221	      }
222	      return;
223	    }
224	
225	    const spHistoryMatch = p.match(/^\/api\/specialists\/([^/]+)\/history$/);
226	    if (spHistoryMatch && req.method === "GET") {
227	      const name = safeDecode(spHistoryMatch[1]);
228	      if (name === null) { json(res, { error: "bad name" }, 400); return; }
229	      const events = getRecentEvents(2000);
230	      const spawns = new Map<string, StateEvent>();
231	      const history: Array<Record<string, unknown>> = [];
232	      for (const e of events) {
233	        if (e.type === "specialist_spawn" &&
234	            ((e.payload.name as string) === name || (e.payload.target as string) === name)) {
235	          const taskId = (e.payload.taskId as string) ?? (e.payload.instanceId as string) ?? e.ts;
236	          spawns.set(taskId, e);
237	        }
238	        if (e.type === "specialist_done" &&
239	            ((e.payload.target as string) === name || (e.payload.name as string) === name)) {
240	          const taskId = (e.payload.taskId as string) ?? "";
241	          const spawn = spawns.get(taskId);
242	          const startTime = spawn?.ts ?? e.ts;
243	          const endTime = e.ts;
244	          const elapsed = Math.round((new Date(endTime).getTime() - new Date(startTime).getTime()) / 1000);
245	          history.push({
246	            taskId,
247	            goal: (e.payload.goal as string) ?? (spawn?.payload.goal as string) ?? "",
248	            status: (e.payload.status as string) ?? (e.payload.error ? "failed" : "done"),
249	            startTime, endTime, elapsedSec: elapsed,
250	            turns: e.payload.turns, verifier: e.payload.verifier,
251	          });
252	        }
253	      }
254	      json(res, history.reverse().slice(0, 20));
255	      return;
256	    }
257	
258	    const spArtifactsMatch = p.match(/^\/api\/specialists\/([^/]+)\/artifacts$/);
259	    if (spArtifactsMatch && req.method === "GET") {
260	      const name = safeDecode(spArtifactsMatch[1]);
261	      if (name === null) { json(res, { error: "bad name" }, 400); return; }
262	      const artifactsDir = path.join(config.memoryDir, "artifacts");
263	      try {
264	        const files = await readdir(artifactsDir);
265	        // 檔名格式 <date>_<taskId>_<specialist>_<slug>.json；taskId 本身可含底線
266	        // （如 pt_codegen_probe），positional split 會解錯，用 specialist name 錨定。
267	        const nameRe = new RegExp(`^(\\d{4}-\\d{2}-\\d{2})_(.+?)_${escapeRegex(name)}_(.+)\\.json$`);
268	        const matched = files.filter((f) => nameRe.test(f)).sort().reverse().slice(0, 20);
269	        const entries = await Promise.all(matched.map(async (f) => {
270	          const m = f.match(nameRe)!;
271	          let sizeBytes = 0;
272	          try { sizeBytes = (await stat(path.join(artifactsDir, f))).size; } catch { /* ignore */ }
273	          return { filename: f, taskId: m[2], slug: m[3], date: m[1], sizeBytes };
274	        }));
275	        json(res, entries);
276	      } catch { json(res, []); }
277	      return;
278	    }
279	
280	    const spFactsMatch = p.match(/^\/api\/specialists\/([^/]+)\/facts$/);
281	    if (spFactsMatch && req.method === "GET") {
282	      const name = safeDecode(spFactsMatch[1]);
283	      if (name === null) { json(res, { error: "bad name" }, 400); return; }
284	      const result = await loadFactsForSpecialist(name);
285	      json(res, result);
286	      return;
287	    }
288	
289	    // ─── Static files ────────────────────────────────────────────────────
290	    if (p === "/" || p === "/index.html") {
291	      try {
292	        const html = await readFile(path.join(staticDir, "index.html"), "utf8");
293	        res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
294	        res.end(html);
295	      } catch {
296	        res.writeHead(500); res.end("index.html not found");
297	      }
298	      return;
299	    }
300	
301	    json(res, { error: "not found" }, 404);
302	    })().catch((err) => {
303	      console.error("[status-server] request error:", err);
304	      if (!res.headersSent) json(res, { error: "internal error" }, 500);
305	      else res.end();
306	    });
307	  });
308	
309	  // 預設只綁 loopback：API 會回 specialist 設定/preamble/facts，不該暴露到 LAN。
310	  // Tunnel（cloudflared/ngrok）連 localhost 即可；要 LAN 直連才設 STATUS_BIND_HOST。
311	  const host = process.env.STATUS_BIND_HOST?.trim() || "127.0.0.1";
312	  httpServer.listen(port, host, () => {
313	    console.log(`[status-server] listening on ${host}:${port}`);
314	  });
315	}
316	
317	export function stopStatusServer(): void {
318	  httpServer?.close();
319	  httpServer = undefined;
320	}
321	
322	// ─── SSE broadcast ─────────────────────────────────────────────────────────
323	
324	/** Broadcast an SSE event to all clients watching a task. */
325	export function broadcastSSE(taskId: string, data: Record<string, unknown>): void {
326	  const clients = sseClients.get(taskId);
327	  if (!clients || clients.size === 0) return;
328	  const payload = `data: ${JSON.stringify(data)}\n\n`;
329	  for (const res of clients) {
330	    res.write(payload);
331	  }
332	}
333	
334	function sseSend(res: ServerResponse, data: Record<string, unknown>): void {
335	  res.write(`data: ${JSON.stringify(data)}\n\n`);
336	}
337	
338	function json(res: ServerResponse, data: unknown, status = 200): void {
339	  res.writeHead(status, { "Content-Type": "application/json" });
340	  res.end(JSON.stringify(data));
341	}
